if !strings.HasPrefix(volume.Source, "group:") {
	// if the volume is a cluster volume and the source is a volumegroup, we
	// will ignore checking to see if such a volume is defined. the volume
	// group isn't namespaced, and there's no simple way to indicate that
	// external volumes with a given group exist.
	stackVolume, exists := stackVolumes[volume.Source]
	if !exists {
		return mount.Mount{}, fmt.Errorf("undefined volume %q", volume.Source)
	}

	// if the volume is not specified with a group source, we may namespace
	// the name, if one is not otherwise specified.
	if stackVolume.Name != "" {
		result.Source = stackVolume.Name
	} else {
		result.Source = namespace.Scope(volume.Source)
	}
}

switch e.Kind {
case token.INT, token.FLOAT, token.IMAG:
	check.langCompat(e)
	// The max. mantissa precision for untyped numeric values
	// is 512 bits, or 4048 bits for each of the two integer
	// parts of a fraction for floating-point numbers that are
	// represented accurately in the go/constant package.
	// Constant literals that are longer than this many bits
	// are not meaningful; and excessively long constants may
	// consume a lot of space and time for a useless conversion.
	// Cap constant length with a generous upper limit that also
	// allows for separators between all digits.
	const limit = 10000
	if len(e.Value) > limit {
		check.errorf(e, InvalidConstVal, "excessively long constant: %s... (%d chars)", e.Value[:10], len(e.Value))
		x.invalidate()
		return
	}
}

switch e.Kind {
case syntax.IntLit, syntax.FloatLit, syntax.ImagLit:
	check.langCompat(e)
	// The max. mantissa precision for untyped numeric values
	// is 512 bits, or 4048 bits for each of the two integer
	// parts of a fraction for floating-point numbers that are
	// represented accurately in the go/constant package.
	// Constant literals that are longer than this many bits
	// are not meaningful; and excessively long constants may
	// consume a lot of space and time for a useless conversion.
	// Cap constant length with a generous upper limit that also
	// allows for separators between all digits.
	const limit = 10000
	if len(e.Value) > limit {
		check.errorf(e, InvalidConstVal, "excessively long constant: %s... (%d chars)", e.Value[:10], len(e.Value))
		x.invalidate()
		return
	}
}

if !l.test {
	// Consume time from in-flight events. Make sure we're not preemptible so allp can't change.
	//
	// The reason we do this instead of just waiting for those events to finish and push updates
	// is to ensure that all the time we're accounting for happened sometime between lastUpdate
	// and now. This dramatically simplifies reasoning about the limiter because we're not at
	// risk of extra time being accounted for in this window than actually happened in this window,
	// leading to all sorts of weird transient behavior.
	mp := acquirem()
	for _, pp := range allp {
		typ, duration := pp.limiterEvent.consume(now)
		switch typ {
		case limiterEventIdle:
			sched.idleTime.Add(duration)
			idleTime += duration
		case limiterEventIdleMarkWork:
			idleTime += duration
		case limiterEventMarkAssist, limiterEventScavengeAssist:
			assistTime += duration
		case limiterEventNone:
			break
		default:
			throw("invalid limiter event type found")
		}
	}
	releasem(mp)
}

if len(failed) > 0 {
	// Something was over-limit, so now we do the more
	// expensive work to report a good error. First, for
	// the over-limit functions, redo the stack check but
	// record the graph this time.
	sc = newStackCheck(ctxt, true)
	for _, s := range failed {
		sc.check(s)
	}

	// Find the roots of the graph (functions that are not
	// called by any other function).
	roots := sc.findRoots()

	// Find and report all paths that go over the limit.
	// This accumulates stack depths top-down. This is
	// much less efficient because we may have to visit
	// the same function multiple times at different
	// depths, but lets us find all paths.
	for _, root := range roots {
		ctxt.Errorf(root, "nosplit stack over %d byte limit", limit)
		chain := []stackCheckChain{{stackCheckEdge{0, root}, false}}
		sc.report(root, limit, &chain)
	}
}

if len(nodeReclaimFuncs) > 0 {
	summary, err := m.summaryProvider.Get(ctx, true)
	if err != nil {
		logger.Error(err, "Eviction manager: failed to get summary stats after resource reclaim")
		return false
	}

	// make observations and get a function to derive pod usage stats relative to those observations.
	observations, _ := makeSignalObservations(logger, summary)
	debugLogObservations(logger, "observations after resource reclaim", observations)

	// evaluate all thresholds independently of their grace period to see if with
	// the new observations, we think we have met min reclaim goals
	thresholds := thresholdsMet(logger, m.config.Thresholds, observations, true)
	debugLogThresholdsWithObservation(logger, "thresholds after resource reclaim - ignoring grace period", thresholds, observations)

	if len(thresholds) == 0 {
		return true
	}
}

switch err {
case nil:
	// successful validation

case jwt.ErrExpired:
	return nil, errors.New("service account token has expired")

case jwt.ErrNotValidYet:
	return nil, errors.New("service account token is not valid yet")

case jwt.ErrIssuedInTheFuture:
	return nil, errors.New("service account token is issued in the future")

// our current use of jwt.Expected above should make these cases impossible to hit
case jwt.ErrInvalidAudience, jwt.ErrInvalidID, jwt.ErrInvalidIssuer, jwt.ErrInvalidSubject:
	klog.Errorf("service account token claim validation got unexpected validation failure: %v", err)
	return nil, fmt.Errorf("service account token claims could not be validated: %w", err) // safe to pass these errors back to the user

default:
	klog.Errorf("service account token claim validation got unexpected error type: %T", err)                         // avoid leaking unexpected information into the logs
	return nil, errors.New("service account token claims could not be validated due to unexpected validation error") // return an opaque error
}

for cursor := 0; cursor < len(input); cursor++ {
	if input[cursor] == operator && cursor+1 < len(input) {
		// Copy the portion of the input string since the last
		// checkpoint into the buffer
		buf.WriteString(input[checkpoint:cursor])

		// Attempt to read the variable name as defined by the
		// syntax from the input string
		read, isVar, advance := tryReadVariableName(input[cursor+1:])

		if isVar {
			// We were able to read a variable name correctly;
			// apply the mapping to the variable name and copy the
			// bytes into the buffer
			buf.WriteString(mapping(read))
		} else {
			// Not a variable name; copy the read bytes into the buffer
			buf.WriteString(read)
		}

		// Advance the cursor in the input string to account for
		// bytes consumed to read the variable name expression
		cursor += advance

		// Advance the checkpoint in the input string
		checkpoint = cursor + 1
	}
}

if maxstale, ok := reqCacheControl["max-stale"]; ok {
	// Indicates that the client is willing to accept a response that has exceeded its expiration time.
	// If max-stale is assigned a value, then the client is willing to accept a response that has exceeded
	// its expiration time by no more than the specified number of seconds.
	// If no value is assigned to max-stale, then the client is willing to accept a stale response of any age.
	//
	// Responses served only because of a max-stale value are supposed to have a Warning header added to them,
	// but that seems like a  hassle, and is it actually useful? If so, then there needs to be a different
	// return-value available here.
	if maxstale == "" {
		return fresh
	}
	maxstaleDuration, err := time.ParseDuration(maxstale + "s")
	if err == nil {
		currentAge = time.Duration(currentAge - maxstaleDuration)
	}
}

switch requestInfo.Verb {
case "list":
	return e.listWorkEstimator.EstimateWork(r, flowSchemaName, priorityLevelName)
case "watch":
	// WATCH supports `SendInitialEvents` option, which effectively means
	// that is starts with sending of the contents of a corresponding LIST call.
	// From that perspective, given that the watch only consumes APF seats
	// during its initialization (sending init events), its cost should then
	// be computed the same way as for a regular list.
	if utilfeature.DefaultFeatureGate.Enabled(features.WatchList) {
		return e.listWorkEstimator.EstimateWork(r, flowSchemaName, priorityLevelName)
	}
case "create", "update", "patch", "delete":
	return e.mutatingWorkEstimator.EstimateWork(r, flowSchemaName, priorityLevelName)
}

switch patchType {
case types.ApplyYAMLPatchType:
	baseContentType = runtime.ContentTypeYAML
case types.ApplyCBORPatchType:
	if !utilfeature.DefaultFeatureGate.Enabled(features.CBORServingAndStorage) {
		// This request should have already been rejected by the
		// Content-Type allowlist check. Return 500 because assumptions are
		// already broken and the feature is not GA.
		utilruntime.HandleErrorWithContext(req.Context(), nil, "The patch content-type allowlist check should have made this unreachable.")
		scope.err(errors.NewInternalError(errors.NewInternalError(fmt.Errorf("unexpected patch type: %v", patchType))), w, req)
		return
	}

	baseContentType = runtime.ContentTypeCBOR
default:
	baseContentType = runtime.ContentTypeJSON
}

if providerID == "" {
	providerID, err = cloudprovider.GetInstanceProviderID(ctx, cnc.cloud, types.NodeName(node.Name))
	if err != nil {
		// This is the only case where ProviderID can be skipped
		if errors.Is(err, cloudprovider.NotImplemented) {
			// if the cloud provider being used does not support provider IDs,
			// we can safely continue since we will attempt to set node
			// addresses given the node name in getNodeAddressesByProviderIDOrName
			klog.Warningf("cloud provider does not set node provider ID, using node name to discover node %s", node.Name)
		} else {
			// if the cloud provider being used supports provider IDs, we want
			// to propagate the error so that we re-try in the future; if we
			// do not, the taint will be removed, and this will not be retried
			return nil, err
		}
	}
}

for _, kubeConfig := range kubeConfigs {
	// create a ReadWriter for certificates embedded in kubeConfig files
	kubeConfigReadWriter := newKubeconfigReadWriter(kubernetesDir, kubeConfig.fileName,
		rm.cfg.CertificatesDir, kubeadmconstants.CACertAndKeyBaseName)

	// adds the certificateRenewHandler.
	// Certificates embedded kubeConfig files in are indexed by fileName, that is a well know constant defined
	// in the kubeadm constants package and that can be reused across all the kubeadm codebase
	rm.certificates[kubeConfig.fileName] = &CertificateRenewHandler{
		Name:       kubeConfig.fileName, // we are using fileName as name, because there is nothing similar outside
		LongName:   kubeConfig.longName,
		FileName:   kubeConfig.fileName,
		CABaseName: kubeadmconstants.CACertAndKeyBaseName, // all certificates in kubeConfig files are signed by the Kubernetes CA
		CAName:     kubeadmconstants.CACertAndKeyBaseName,
		readwriter: kubeConfigReadWriter,
	}
}

for _, slice := range resourceSlices {
	for _, device := range slice.Spec.Devices {
		// Make sure all consumed counters for the device references counter sets that exists and
		// that they consume counters that exists within those counter sets.
		for _, deviceCounterConsumption := range device.ConsumesCounters {
			counterSet, found := counterSets[deviceCounterConsumption.CounterSet]
			if !found {
				return fmt.Errorf("counter set %s not found", deviceCounterConsumption.CounterSet)
			}

			for counterName := range deviceCounterConsumption.Counters {
				if _, found := counterSet.Counters[counterName]; !found {
					return fmt.Errorf("counter %s not found in counter set %s", counterName, counterSet.Name)
				}
			}
		}
	}
}

switch {
case !found:
	// flag it to be cleaned up after any races (hopefully) are gone
	runtime.HandleError(fmt.Errorf("the cluster IP %s may have leaked: flagging for later clean up", ip))
	count = numRepairsBeforeLeakCleanup - 1
	fallthrough
case count > 0:
	// pretend it is still in use until count expires
	leaks[ip.String()] = count - 1
	if err := rebuilt.Allocate(ip); err != nil {
		// do not increment the metric here, if it is a leak it will be detected once the counter gets to 0
		runtime.HandleError(fmt.Errorf("the cluster IP %s may have leaked, but can not be allocated: %v", ip, err))
	}
default:
	clusterIPRepairIPErrors.WithLabelValues("leak").Inc()
	// do not add it to the rebuilt set, which means it will be available for reuse
	runtime.HandleError(fmt.Errorf("the cluster IP %s appears to have leaked: cleaning up", ip))
}

switch {
case !found:
	// flag it to be cleaned up after any races (hopefully) are gone
	runtime.HandleError(fmt.Errorf("the node port %d may have leaked: flagging for later clean up", port))
	count = numRepairsBeforeLeakCleanup - 1
	fallthrough
case count > 0:
	// pretend it is still in use until count expires
	c.leaks[port] = count - 1
	if err := rebuilt.Allocate(port); err != nil {
		// do not increment the metric here, if it is a leak it will be detected once the counter gets to 0
		runtime.HandleError(fmt.Errorf("the node port %d may have leaked, but can not be allocated: %v", port, err))
	}
default:
	nodePortRepairPortErrors.WithLabelValues("leak").Inc()
	// do not add it to the rebuilt set, which means it will be available for reuse
	runtime.HandleError(fmt.Errorf("the node port %d appears to have leaked: cleaning up", port))
}

for _, condition := range oldConditions {
	// If Condition is of not resize type, we keep it.
	if _, ok := knownResizeConditions[condition.Type]; !ok {
		newConditions = append(newConditions, condition)
		continue
	}

	if newCondition, ok := resizeConditionMap[condition.Type]; ok {
		if newCondition.condition.Status != condition.Status {
			newConditions = append(newConditions, newCondition.condition)
		} else {
			newConditions = append(newConditions, condition)
		}
		newCondition.processed = true
	} else if keepOldResizeConditions {
		// if keepOldResizeConditions is true, we keep the old resize conditions that were present in the
		// existing pvc.Status.Conditions field.
		newConditions = append(newConditions, condition)
	}
}

for _, r := range labelReconcileInfo {
	primaryValue, primaryExists := node.Labels[r.primaryKey]
	secondaryValue, secondaryExists := node.Labels[r.secondaryKey]

	if !primaryExists {
		// The primary label key does not exist. This should not happen
		// within our supported version skew range, when no external
		// components/factors modifying the node object. Ignore this case.
		continue
	}
	if secondaryExists && primaryValue != secondaryValue {
		// Secondary label exists, but not consistent with the primary
		// label. Need to reconcile.
		labelsToUpdate[r.secondaryKey] = primaryValue

	} else if !secondaryExists && r.ensureSecondaryExists {
		// Apply secondary label based on primary label.
		labelsToUpdate[r.secondaryKey] = primaryValue
	}
}

if isSidecarContainer(pod, container) {
	// check min memory quantity in regular containers
	minMemoryRequest := minRegularContainerMemory(*pod)

	// When calculating minMemoryOomScoreAdjust for sidecar containers with PodLevelResources enabled,
	// we add the per-container share of unallocated pod memory requests to the minimum memory request.
	// This ensures the OOM score adjustment i.e. minMemoryOomScoreAdjust
	// calculation remains consistent
	//  with how we handle pod-level memory requests for regular containers.
	if utilfeature.DefaultFeatureGate.Enabled(features.PodLevelResources) &&
		resourcehelper.IsPodLevelRequestsSet(pod) {
		minMemoryRequest += remainingReqPerContainer
	}
	minMemoryOomScoreAdjust := 1000 - (1000*minMemoryRequest)/memoryCapacity
	// the OOM adjustment for sidecar container will match
	// or fall below the OOM score adjustment of regular containers in the Pod.
	if oomScoreAdjust > minMemoryOomScoreAdjust {
		oomScoreAdjust = minMemoryOomScoreAdjust
	}
}

for gv, enabled := range resourceConfig.GroupVersionConfigs {
	ret.GroupVersionConfigs[gv] = enabled
	if !enabled {
		continue
	}
	// emulation forward compatibility is not applicable to alpha apis.
	if alphaPattern.MatchString(gv.Version) {
		continue
	}
	// if a gv is enabled, all the versions with higher priority (all the versions before gv in PrioritizedVersionsForGroup) are also implicitly enabled for emulation forward compatibility.
	prioritizedVersions := registry.PrioritizedVersionsForGroup(gv.Group)
	sort.Slice(prioritizedVersions, func(i, j int) bool {
		return version.CompareKubeAwareVersionStrings(prioritizedVersions[i].Version, prioritizedVersions[j].Version) > 0
	})
	for _, pgv := range prioritizedVersions {
		if pgv.Version == gv.Version {
			break
		}
		ret.EnableVersions(pgv)
	}
}

for gvr, enabled := range resourceConfig.ResourceConfigs {
	ret.ResourceConfigs[gvr] = enabled
	if !enabled {
		continue
	}
	// emulation forward compatibility is not applicable to alpha apis.
	if alphaPattern.MatchString(gvr.Version) {
		continue
	}
	// if a gvr is enabled, all the versions with the same resource name and higher priority (all the versions before gv in PrioritizedVersionsForGroup) are also implicitly enabled for emulation forward compatibility.
	prioritizedVersions := registry.PrioritizedVersionsForGroup(gvr.Group)
	sort.Slice(prioritizedVersions, func(i, j int) bool {
		return version.CompareKubeAwareVersionStrings(prioritizedVersions[i].Version, prioritizedVersions[j].Version) > 0
	})
	for _, pgv := range prioritizedVersions {
		if pgv.Version == gvr.Version {
			break
		}
		ret.EnableResources(pgv.WithResource(gvr.Resource))
	}
}

for name, spec := range in {
	converted := featuregate.FeatureSpec{
		Default:       spec.Default,
		LockToDefault: spec.LockToDefault,
	}
	switch spec.PreRelease {
	case clientfeatures.Alpha:
		converted.PreRelease = featuregate.Alpha
	case clientfeatures.Beta:
		converted.PreRelease = featuregate.Beta
	case clientfeatures.GA:
		converted.PreRelease = featuregate.GA
	case clientfeatures.Deprecated:
		converted.PreRelease = featuregate.Deprecated
	default:
		// The default case implies programmer error.  The same set of prerelease
		// constants must exist in both component-base and client-go, and each one
		// must have a case here.
		panic(fmt.Sprintf("unrecognized prerelease %q of feature %q", spec.PreRelease, name))
	}
	out[featuregate.Feature(name)] = converted
}

for _, nodeIP := range nodeIPs {
	// For every address supplied by the cloud provider that matches nodeIP,
	// nodeIP is the enforced node address for that address Type (like
	// InternalIP and ExternalIP), meaning other addresses of the same Type
	// are discarded. See #61921 for more information: some cloud providers
	// may supply secondary IPs, so nodeIP serves as a way to ensure that the
	// correct IPs show up on a Node object.

	matched := false
	for _, nodeAddress := range cloudNodeAddresses {
		if netutils.ParseIPSloppy(nodeAddress.Address).Equal(nodeIP) {
			enforcedNodeAddresses = append(enforcedNodeAddresses, v1.NodeAddress{Type: nodeAddress.Type, Address: nodeAddress.Address})
			nodeIPTypes[nodeAddress.Type] = true
			matched = true
		}
	}

	// nodeIP must be among the addresses supplied by the cloud provider
	if !matched {
		return nil, fmt.Errorf("failed to get node address from cloud provider that matches ip: %v", nodeIP)
	}
}

if cached == nil {
	// There was an error fetching discovery for this APIService, and
	// there is nothing in the cache for this GV.
	//
	// Just use empty GV to mark that GV exists, but no resources.
	// Also mark that it is stale to indicate the fetch failed
	// TODO: Maybe also stick in a status for the version the error?
	entry = apidiscoveryv2.APIVersionDiscovery{
		Version: gv.Version,
	}
} else {
	// Find our specific groupversion within the discovery document
	entry, exists = cached.discovery[mgv]
	if exists {
		// The stale/fresh entry has our GV, so we can include it in the doc
	} else {
		// Successfully fetched discovery information from the server, but
		// the server did not include this groupversion?
		entry = apidiscoveryv2.APIVersionDiscovery{
			Version: gv.Version,
		}
	}
}

for name, specs := range in {
	convertedSpecs := make(featuregate.VersionedSpecs, len(specs))
	for i, spec := range specs {
		converted := featuregate.FeatureSpec{
			Default:       spec.Default,
			LockToDefault: spec.LockToDefault,
			Version:       spec.Version,
		}
		switch spec.PreRelease {
		case clientfeatures.Alpha:
			converted.PreRelease = featuregate.Alpha
		case clientfeatures.Beta:
			converted.PreRelease = featuregate.Beta
		case clientfeatures.GA:
			converted.PreRelease = featuregate.GA
		case clientfeatures.Deprecated:
			converted.PreRelease = featuregate.Deprecated
		default:
			// The default case implies programmer error.  The same set of prerelease
			// constants must exist in both component-base and client-go, and each one
			// must have a case here.
			panic(fmt.Sprintf("unrecognized prerelease %q of feature %q", spec.PreRelease, name))
		}
		convertedSpecs[i] = converted
	}
	out[featuregate.Feature(name)] = convertedSpecs
}

switch listType {
case "map":
	// Look up keys for this index in current object
	currentElement := asList[index]

	oldList := r.mapList
	if oldList == nil {
		oldList = MakeMapList(r.Schema, oldAsList)
		r.mapList = oldList
	}
	return oldList.Get(currentElement)

case "set":
	// Are sets correlatable? Only if the old value equals the current value.
	// We might be able to support this, but do not currently see a lot
	// of value
	// (would allow you to add/remove items from sets with ratcheting but not change them)
	return nil
case "":
	fallthrough
case "atomic":
	// Atomic lists are the default are not correlatable by item
	// Ratcheting is not available on a per-index basis
	return nil
default:
	// Unrecognized list type. Assume non-correlatable.
	return nil
}

if namespace, name, ok := isServiceAccountUsername(username); ok {
	usernameAttributes.Resource = "serviceaccounts"
	usernameAttributes.Namespace = namespace
	usernameAttributes.Name = name

	// this should be impossible to reach but check just in case
	if m.isConstrainedImpersonation && len(wantedUserGroups) != 0 {
		return responsewriters.ForbiddenStatusError(usernameAttributes, fmt.Sprintf("when impersonating a service account, cannot impersonate groups %q", wantedUserGroups))
	}

	if len(wantedUserGroups) == 0 {
		// if groups are not specified for a service account, we know the groups because it is a fixed mapping.  Add them
		actualUser.Groups = serviceaccount.MakeGroupNames(namespace)
	}
}

for _, ref := range newBlockingRefs {
	records, err := a.ownerRefToDeleteAttributeRecords(ref, attributes)
	if err != nil {
		return admission.NewForbidden(attributes, fmt.Errorf("cannot set blockOwnerDeletion in this case because cannot find RESTMapping for APIVersion %s Kind %s: %v", ref.APIVersion, ref.Kind, err))
	}
	// Multiple records are returned if ref.Kind could map to multiple
	// resources. User needs to have delete permission on all the
	// matched Resources.
	for _, record := range records {
		decision, reason, err := a.authorizer.Authorize(ctx, record)
		if decision != authorizer.DecisionAllow {
			return admission.NewForbidden(attributes, fmt.Errorf("cannot set blockOwnerDeletion if an ownerReference refers to a resource you can't set finalizers on: %v, %v", reason, err))
		}
	}
}
